function active$FormPurchaseEmployee(f) {f.add_onResponseComplete(on$FormPurchaseEmployee$ResponseComplete);}
function close$FormPurchaseEmployee(f) {try {f.remove_onResponseComplete(on$FormPurchaseEmployee$ResponseComplete)} catch (ex) {}}
function on$FormPurchaseEmployee$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'ma_nvmh');
      break;
    default:
      break;
  }
}      

      &ScriptIrregular;
